-- Name: backup_critical_tables(); Type: PROCEDURE; Schema: public; Owner: postgres
--

CREATE PROCEDURE public.backup_critical_tables()
    LANGUAGE plpgsql
    AS $$
DECLARE
    backup_table_name TEXT;
BEGIN
    -- Backup asha_reports
    backup_table_name := 'asha_reports_backup_' || TO_CHAR(NOW(), 'YYYYMMDD_HH24MISS');
    EXECUTE format('CREATE TABLE %I AS SELECT * FROM public.asha_reports', backup_table_name);
    
    -- Log backup
    VALUES (NULL, 'DATABASE_BACKUP', format('Created backup table: %s', backup_table_name));
END;
$$;


ALTER PROCEDURE public.backup_critical_tables() OWNER TO postgres;

