-- TOC entry 1514 (class 1255 OID 30894)
-- Name: check_hospital_user_exists(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.check_hospital_user_exists(p_facility_id integer) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_exists BOOLEAN;
BEGIN
    SELECT EXISTS (
        SELECT 1 FROM public.users 
        WHERE facility_id = p_facility_id AND role = 'HOSPITAL'
    ) INTO v_exists;
    
    RETURN v_exists;
END;
$$;


