-- TOC entry 1424 (class 1255 OID 30861)
-- Name: generate_daily_summary(); Type: PROCEDURE; Schema: public; Owner: postgres
--

CREATE PROCEDURE public.generate_daily_summary()
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Insert into a summary table (create it first if needed)
    CREATE TABLE IF NOT EXISTS public.daily_summary_archive (
        id SERIAL PRIMARY KEY,
        report_date DATE,
        total_reports INTEGER,
        total_cases INTEGER,
        active_workers INTEGER,
        created_at TIMESTAMP DEFAULT NOW()
    );
    
    SELECT 
        CURRENT_DATE - INTERVAL '1 day',
        COUNT(*),
        SUM(fever_count + cough_count + diarrhea_count),
        COUNT(DISTINCT worker_id)
    FROM public.asha_reports
    WHERE report_date = CURRENT_DATE - INTERVAL '1 day';
    
    -- Log the operation
    VALUES (NULL, 'DAILY_SUMMARY', 'Daily summary generated for ' || (CURRENT_DATE - INTERVAL '1 day')::text);
END;
$$;


ALTER PROCEDURE public.generate_daily_summary() OWNER TO postgres;

