-- TOC entry 4404 (class 1255 OID 30872)
-- Name: get_database_stats(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_database_stats() RETURNS TABLE(table_name text, row_count bigint, table_size text, index_size text)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        relname::TEXT,
        n_live_tup::BIGINT,
        pg_size_pretty(pg_table_size(relid)) as table_size,
        pg_size_pretty(pg_indexes_size(relid)) as index_size
    FROM pg_stat_user_tables
    WHERE schemaname = 'public'
    ORDER BY n_live_tup DESC;
END;
$$;


