--
-- TOC entry 971 (class 1255 OID 30481)
-- Name: latest_report_date(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.latest_report_date() RETURNS date
    LANGUAGE plpgsql IMMUTABLE
    AS $$
DECLARE
    latest DATE;
BEGIN
    SELECT MAX(report_date) INTO latest
    FROM (
        SELECT report_date FROM public.asha_reports
        UNION ALL
        SELECT report_date FROM public.capacity_reports
    ) AS all_reports;
    RETURN COALESCE(latest, CURRENT_DATE);
END;
$$;


