--
-- TOC entry 4306 (class 1255 OID 30895)
-- Name: register_hospital(character varying, character varying, numeric, numeric, character varying, character varying, text, jsonb, character varying, character varying, character varying); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.register_hospital(p_facility_name character varying, p_ward_code character varying, p_location_lat numeric, p_location_lng numeric, p_contact character varying, p_facility_type character varying, p_address text, p_specialties jsonb, p_username character varying, p_password_hash character varying, p_full_name character varying) RETURNS TABLE(facility_id integer, user_id integer, success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_facility_id INTEGER;
    v_user_id INTEGER;
BEGIN
    -- Start transaction
    BEGIN
        -- Insert facility
            name, ward_code, location_lat, location_lng, contact, 
            facility_type, address, specialties, type, oxygen_status
        ) VALUES (
            p_facility_name, p_ward_code, p_location_lat, p_location_lng, 
            p_contact, p_facility_type, p_address, p_specialties,
            'GOVERNMENT', 'STABLE'
        ) RETURNING id INTO v_facility_id;
        
        -- Insert hospital user
            username, password_hash, role, facility_id, full_name
        ) VALUES (
            p_username, p_password_hash, 'HOSPITAL', v_facility_id, p_full_name
        ) RETURNING id INTO v_user_id;
        
        -- Return success
        RETURN QUERY SELECT 
            v_facility_id, 
            v_user_id, 
            TRUE, 
            'Hospital registered successfully'::TEXT;
            
    EXCEPTION WHEN OTHERS THEN
        -- Rollback is automatic in a function
        RETURN QUERY SELECT 
            NULL::INTEGER, 
            NULL::INTEGER, 
            FALSE, 
            SQLERRM::TEXT;
    END;
END;
$$;


