--
-- TOC entry 3124 (class 1255 OID 30860)
-- Name: update_inventory_after_distribution(integer, character varying, integer); Type: PROCEDURE; Schema: public; Owner: postgres
--

CREATE PROCEDURE public.update_inventory_after_distribution(IN p_facility_id integer, IN p_resource_type character varying, IN p_quantity_used integer)
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE public.facility_inventory
    SET current_stock = current_stock - p_quantity_used,
        last_updated = NOW()
    WHERE facility_id = p_facility_id 
      AND resource_type = p_resource_type;
    
    -- Create audit log
    VALUES (NULL, 'INVENTORY_UPDATE', 
            format('Updated inventory for facility %s: %s reduced by %s units', 
                   p_facility_id, p_resource_type, p_quantity_used));
END;
$$;


