--
-- TOC entry 398 (class 1259 OID 30845)
-- Name: v_active_critical_alerts; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.v_active_critical_alerts AS
 SELECT a.id,
    a.type,
    a.severity,
    a.ward_code,
    w.name AS ward_name,
    a.title,
    a.description,
    a.generated_at,
    a.status,
        CASE
            WHEN (a.acknowledged_at IS NULL) THEN 'Not Acknowledged'::text
            WHEN (a.resolved_at IS NULL) THEN 'Acknowledged but Not Resolved'::text
            ELSE 'Resolved'::text
        END AS resolution_status
   FROM (public.alerts a
     LEFT JOIN public.wards w ON (((a.ward_code)::text = (w.code)::text)))
  WHERE (((a.status)::text = 'active'::text) OR (((a.status)::text = 'acknowledged'::text) AND (a.resolved_at IS NULL)))
  ORDER BY ((a.severity)::text = 'critical'::text) DESC, a.generated_at DESC;


ALTER VIEW public.v_active_critical_alerts OWNER TO postgres;

--
-- TOC entry 387 (class 1259 OID 30482)
-- Name: v_asha_performance; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.v_asha_performance AS
 WITH report_counts AS (
         SELECT asha_reports.worker_id,
            count(*) AS submitted_reports,
            max(asha_reports.report_date) AS last_report
           FROM public.asha_reports
          WHERE (asha_reports.report_date >= (public.latest_asha_date() - '7 days'::interval))
          GROUP BY asha_reports.worker_id
        )
 SELECT u.id,
    u.full_name AS name,
    u.ward_code AS assigned_ward,
    u.last_sync_time AS last_sync,
    COALESCE(rc.submitted_reports, (0)::bigint) AS submitted_reports,
    COALESCE(w.target_daily_reports, 50) AS target,
        CASE
            WHEN (rc.last_report < (public.latest_asha_date() - '1 day'::interval)) THEN 'Overdue'::text
            ELSE 'Active'::text
        END AS status,
    false AS out_of_bounds
   FROM ((public.users u
     LEFT JOIN report_counts rc ON ((u.id = rc.worker_id)))
     LEFT JOIN public.wards w ON (((u.ward_code)::text = (w.code)::text)))
  WHERE ((u.role)::text = 'ASHA'::text);


ALTER VIEW public.v_asha_performance OWNER TO postgres;

--
-- TOC entry 400 (class 1259 OID 30855)
-- Name: v_asha_ranking; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.v_asha_ranking AS
 SELECT u.id,
    u.full_name,
    u.ward_code,
    w.name AS ward_name,
    count(ar.id) AS reports_30d,
    sum(((ar.fever_count + ar.cough_count) + ar.diarrhea_count)) AS total_cases_reported,
    max(ar.report_date) AS last_report_date,
    round(((count(ar.id))::numeric / (NULLIF(w.target_daily_reports, 0))::numeric), 2) AS target_achievement_ratio,
    row_number() OVER (ORDER BY (count(ar.id)) DESC) AS rank
   FROM ((public.users u
     LEFT JOIN public.asha_reports ar ON (((u.id = ar.worker_id) AND (ar.report_date >= (CURRENT_DATE - '30 days'::interval)))))
     LEFT JOIN public.wards w ON (((u.ward_code)::text = (w.code)::text)))
  WHERE ((u.role)::text = 'ASHA'::text)
  GROUP BY u.id, u.full_name, u.ward_code, w.name, w.target_daily_reports
  ORDER BY (count(ar.id)) DESC;


ALTER VIEW public.v_asha_ranking OWNER TO postgres;

--
-- TOC entry 396 (class 1259 OID 30835)
-- Name: v_daily_summary; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.v_daily_summary AS
 SELECT report_date,
    count(DISTINCT worker_id) AS active_workers,
    count(*) AS total_reports,
    sum(fever_count) AS total_fever,
    sum(cough_count) AS total_cough,
    sum(diarrhea_count) AS total_diarrhea,
    sum(jaundice_count) AS total_jaundice,
    sum(rash_count) AS total_rash
   FROM public.asha_reports
  WHERE (report_date >= (CURRENT_DATE - '30 days'::interval))
  GROUP BY report_date
  ORDER BY report_date DESC;


ALTER VIEW public.v_daily_summary OWNER TO postgres;

