  ORDER BY report_date;


ALTER VIEW public.v_epi_curve OWNER TO postgres;

--
-- TOC entry 399 (class 1259 OID 30850)
-- Name: v_facility_capacity_status; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.v_facility_capacity_status AS
 WITH latest_capacity AS (
         SELECT DISTINCT ON (capacity_reports.facility_id) capacity_reports.facility_id,
            capacity_reports.beds_total,
            capacity_reports.beds_available,
            capacity_reports.icu_total,
            capacity_reports.icu_available,
            capacity_reports.ventilators_total,
            capacity_reports.ventilators_available,
            capacity_reports.oxygen_available,
            capacity_reports.report_date,
            round((((capacity_reports.beds_available)::numeric / (NULLIF(capacity_reports.beds_total, 0))::numeric) * (100)::numeric), 2) AS bed_utilization_rate,
            round((((capacity_reports.icu_available)::numeric / (NULLIF(capacity_reports.icu_total, 0))::numeric) * (100)::numeric), 2) AS icu_utilization_rate
           FROM public.capacity_reports
          ORDER BY capacity_reports.facility_id, capacity_reports.report_date DESC
        )
 SELECT f.id,
    f.name,
    f.ward_code,
    w.name AS ward_name,
    f.facility_type,
    lc.beds_total,
    lc.beds_available,
    lc.bed_utilization_rate,
    lc.icu_total,
    lc.icu_available,
    lc.icu_utilization_rate,
    lc.ventilators_total,
    lc.ventilators_available,
    lc.oxygen_available,
    lc.report_date AS last_updated,
        CASE
            WHEN (lc.bed_utilization_rate > (90)::numeric) THEN 'Critical'::text
            WHEN (lc.bed_utilization_rate > (75)::numeric) THEN 'High'::text
            WHEN (lc.bed_utilization_rate > (50)::numeric) THEN 'Medium'::text
            ELSE 'Normal'::text
        END AS bed_status
   FROM ((public.facilities f
     LEFT JOIN latest_capacity lc ON ((f.id = lc.facility_id)))
     LEFT JOIN public.wards w ON (((f.ward_code)::text = (w.code)::text)));


ALTER VIEW public.v_facility_capacity_status OWNER TO postgres;

--
-- TOC entry 410 (class 1259 OID 31106)
-- Name: v_facility_performance; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.v_facility_performance AS
 WITH latest_reports AS (
         SELECT DISTINCT ON (capacity_reports.facility_id) capacity_reports.facility_id,
            capacity_reports.report_date,
            capacity_reports.beds_available,
            capacity_reports.beds_total,
            capacity_reports.icu_available,
            capacity_reports.icu_total,
            capacity_reports.oxygen_available
           FROM public.capacity_reports
          ORDER BY capacity_reports.facility_id, capacity_reports.report_date DESC
        ), report_counts AS (
         SELECT capacity_reports.facility_id,
            count(*) AS reports_sent,
            round((((count(*))::numeric / (7)::numeric) * (100)::numeric), 1) AS compliance_percentage
           FROM public.capacity_reports
          WHERE (capacity_reports.report_date >= (CURRENT_DATE - '7 days'::interval))
          GROUP BY capacity_reports.facility_id
        )
 SELECT f.id,
    f.name,
    f.type,
    f.ward_code,
    f.specialties,
    f.doctors,
    f.location_lat AS lat,
    f.location_lng AS lng,
    COALESCE(rc.compliance_percentage, (0)::numeric) AS compliance_percentage,
    COALESCE(lr.beds_available, 0) AS beds_available,
    COALESCE(lr.beds_total, 0) AS beds_total,
    COALESCE(lr.icu_available, 0) AS icu_available,
    COALESCE(lr.icu_total, 0) AS icu_total,
    COALESCE(lr.oxygen_available, false) AS oxygen_available,
    lr.report_date AS last_reported
   FROM ((public.facilities f
     LEFT JOIN latest_reports lr ON ((f.id = lr.facility_id)))
     LEFT JOIN report_counts rc ON ((f.id = rc.facility_id)));


ALTER VIEW public.v_facility_performance OWNER TO postgres;

--
-- TOC entry 404 (class 1259 OID 30901)
