--
-- TOC entry 403 (class 1259 OID 30896)
-- Name: v_hospital_dashboard; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.v_hospital_dashboard AS
 SELECT f.id AS facility_id,
    f.name AS facility_name,
    f.ward_code,
    w.name AS ward_name,
    f.facility_type,
    f.contact,
    f.address,
    f.specialties,
    cr.beds_total,
    cr.beds_available,
    cr.icu_total,
    cr.icu_available,
    cr.ventilators_total,
    cr.ventilators_available,
    cr.oxygen_available,
    cr.report_date AS last_capacity_report,
    round((((cr.beds_available)::numeric / (NULLIF(cr.beds_total, 0))::numeric) * (100)::numeric), 2) AS bed_utilization,
    jsonb_agg(jsonb_build_object('resource_type', fi.resource_type, 'current_stock', fi.current_stock, 'min_threshold', fi.min_threshold, 'status',
        CASE
            WHEN (fi.current_stock < fi.min_threshold) THEN 'CRITICAL'::text
            WHEN ((fi.current_stock)::numeric < ((fi.min_threshold)::numeric * 1.5)) THEN 'LOW'::text
            ELSE 'OK'::text
        END)) AS inventory_status
   FROM (((public.facilities f
     LEFT JOIN public.wards w ON (((f.ward_code)::text = (w.code)::text)))
     LEFT JOIN LATERAL ( SELECT capacity_reports.id,
            capacity_reports.facility_id,
            capacity_reports.report_date,
            capacity_reports.beds_total,
            capacity_reports.beds_available,
            capacity_reports.icu_total,
            capacity_reports.icu_available,
            capacity_reports.ventilators_total,
            capacity_reports.ventilators_available,
            capacity_reports.oxygen_available,
            capacity_reports.disease_counts,
            capacity_reports.created_at
           FROM public.capacity_reports
          WHERE (capacity_reports.facility_id = f.id)
          ORDER BY capacity_reports.report_date DESC
         LIMIT 1) cr ON (true))
     LEFT JOIN public.facility_inventory fi ON ((f.id = fi.facility_id)))
  GROUP BY f.id, f.name, f.ward_code, w.name, f.facility_type, f.contact, f.address, f.specialties, cr.beds_total, cr.beds_available, cr.icu_total, cr.icu_available, cr.ventilators_total, cr.ventilators_available, cr.oxygen_available, cr.report_date;


ALTER VIEW public.v_hospital_dashboard OWNER TO postgres;

