-- TOC entry 389 (class 1259 OID 30496)
-- Name: v_inventory_burn_rate; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.v_inventory_burn_rate AS
 WITH daily_consumption AS (
         SELECT ar.ward_code,
            drm.resource_type,
            count(*) AS daily_consumption
           FROM (public.asha_reports ar
             JOIN public.disease_resource_mapping drm ON (((((drm.disease)::text = 'fever'::text) AND (ar.fever_count > 0)) OR (((drm.disease)::text = 'cough'::text) AND (ar.cough_count > 0)) OR (((drm.disease)::text = 'diarrhea'::text) AND (ar.diarrhea_count > 0)))))
          WHERE (ar.report_date >= (public.latest_report_date() - '7 days'::interval))
          GROUP BY ar.ward_code, drm.resource_type
        ), inventory_per_ward AS (
         SELECT f.ward_code,
            fi.resource_type,
            fi.current_stock,
            fi.min_threshold,
            fi.last_updated
           FROM (public.facility_inventory fi
             JOIN public.facilities f ON ((fi.facility_id = f.id)))
        )
 SELECT i.ward_code,
    i.resource_type,
    i.current_stock,
    COALESCE(dc.daily_consumption, (0)::bigint) AS daily_consumption,
        CASE
            WHEN (COALESCE(dc.daily_consumption, (0)::bigint) > 0) THEN (i.current_stock / dc.daily_consumption)
            ELSE (999)::bigint
        END AS days_until_depletion
   FROM (inventory_per_ward i
     LEFT JOIN daily_consumption dc ON ((((i.ward_code)::text = (dc.ward_code)::text) AND ((i.resource_type)::text = (dc.resource_type)::text))));


ALTER VIEW public.v_inventory_burn_rate OWNER TO postgres;

--
-- TOC entry 390 (class 1259 OID 30501)
-- Name: v_mo_metrics; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.v_mo_metrics AS
 WITH case_counts AS (
         SELECT v_epi_curve.total_cases
           FROM public.v_epi_curve
          WHERE (v_epi_curve.report_date >= (public.latest_asha_date() - '7 days'::interval))
        ), burn_rate AS (
         SELECT count(*) AS low_stock_count
           FROM public.v_inventory_burn_rate
          WHERE (v_inventory_burn_rate.days_until_depletion < 2)
        )
 SELECT ( SELECT avg(case_counts_1.total_cases) AS avg
           FROM case_counts case_counts_1) AS moving_average_7d,
    0 AS test_positivity_rate,
    0 AS asha_conversion_rate,
    ( SELECT burn_rate.low_stock_count
           FROM burn_rate) AS resources_low_stock,
    public.latest_asha_date() AS reference_date
   FROM case_counts
 LIMIT 1;


ALTER VIEW public.v_mo_metrics OWNER TO postgres;

--
-- TOC entry 409 (class 1259 OID 31101)
-- Name: v_ward_risk_intelligence; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.v_ward_risk_intelligence AS
 WITH ward_metrics AS (
         SELECT w.code AS ward_code,
            w.name AS ward_name,
            w.total_population,
            COALESCE(sum(((r.fever_count + r.cough_count) + r.diarrhea_count)) FILTER (WHERE (r.report_date >= (CURRENT_DATE - '7 days'::interval))), (0)::bigint) AS current_cases,
            COALESCE(sum(((r.fever_count + r.cough_count) + r.diarrhea_count)) FILTER (WHERE ((r.report_date >= (CURRENT_DATE - '14 days'::interval)) AND (r.report_date < (CURRENT_DATE - '7 days'::interval)))), (0)::bigint) AS previous_cases,
            max(r.report_date) AS last_report_date
           FROM (public.wards w
             LEFT JOIN public.asha_reports r ON (((w.code)::text = (r.ward_code)::text)))
          GROUP BY w.code, w.name, w.total_population
        )
 SELECT ward_code,
    ward_name,
    current_cases,
        CASE
            WHEN (previous_cases = 0) THEN (0)::numeric
            ELSE round(((((current_cases)::numeric - (previous_cases)::numeric) / (previous_cases)::numeric) * (100)::numeric), 2)
        END AS trend,
    LEAST(round(((((current_cases)::numeric / (NULLIF(total_population, 0))::numeric) * (1000)::numeric) * (5)::numeric), 2), (100)::numeric) AS risk_score,
    ((last_report_date < (CURRENT_DATE - '2 days'::interval)) OR (last_report_date IS NULL)) AS is_stale
   FROM ward_metrics;


ALTER VIEW public.v_ward_risk_intelligence OWNER TO postgres;

--
-- TOC entry 397 (class 1259 OID 30840)
-- Name: v_ward_weekly_summary; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.v_ward_weekly_summary AS
 SELECT w.code AS ward_code,
    w.name AS ward_name,
    date_trunc('week'::text, (ar.report_date)::timestamp with time zone) AS week_start,
    count(DISTINCT ar.worker_id) AS active_ashas,
    count(ar.id) AS total_reports,
    sum(ar.fever_count) AS fever_cases,
    sum(ar.cough_count) AS cough_cases,
    sum(ar.diarrhea_count) AS diarrhea_cases,
    sum(((ar.fever_count + ar.cough_count) + ar.diarrhea_count)) AS total_cases,
    round(avg(((ar.fever_count + ar.cough_count) + ar.diarrhea_count)), 2) AS avg_cases_per_report
   FROM (public.wards w
     LEFT JOIN public.asha_reports ar ON (((w.code)::text = (ar.ward_code)::text)))
  WHERE (ar.report_date >= (CURRENT_DATE - '90 days'::interval))
  GROUP BY w.code, w.name, (date_trunc('week'::text, (ar.report_date)::timestamp with time zone))
  ORDER BY (date_trunc('week'::text, (ar.report_date)::timestamp with time zone)) DESC, (sum(((ar.fever_count + ar.cough_count) + ar.diarrhea_count))) DESC;


